CREATE VIEW crypto.int_price_metrics AS
 WITH klines AS (
         SELECT stg_raw_binance_klines.symbol,
            stg_raw_binance_klines.open_time,
            stg_raw_binance_klines.close_time,
            stg_raw_binance_klines.open_price,
