           FROM crypto.stg_raw_binance_klines
        ), price_metrics AS (
         SELECT klines.symbol,
            klines.open_time,
            klines.close_time,
            klines.open_price,
            klines.close_price,
            klines.high_price,
            klines.low_price,
            klines.volume,
            (klines.close_price - klines.open_price) AS price_change,
            (((klines.close_price - klines.open_price) / klines.open_price) * (100)::numeric) AS price_change_percent,
            (klines.high_price - klines.low_price) AS price_range
           FROM klines
        )
 SELECT symbol,
    open_time,
    close_time,
    open_price,
