CREATE VIEW crypto.int_symbol_volume AS
 WITH trades AS (
         SELECT stg_raw_binance_trades.symbol,
            stg_raw_binance_trades.trade_time,
            stg_raw_binance_trades.quantity,
            stg_raw_binance_trades.quote_quantity
           FROM crypto.stg_raw_binance_trades
        ), trade_values AS (
         SELECT trades.symbol,
            trades.trade_time,
            trades.quantity,
            trades.quote_quantity,
            (trades.quantity * trades.quote_quantity) AS trade_value
           FROM trades
        ), aggregated_volume AS (
         SELECT trade_values.symbol,
            date(trade_values.trade_time) AS trade_date,
            sum(trade_values.quantity) AS total_quantity_traded,
            sum(trade_values.quote_quantity) AS total_quote_volume,
            sum(trade_values.trade_value) AS total_trade_value,
            count(*) AS number_of_trades
           FROM trade_values
          GROUP BY trade_values.symbol, (date(trade_values.trade_time))
        )
 SELECT symbol,
    trade_date,
    total_quantity_traded,
    total_quote_volume,
    total_trade_value,
    number_of_trades
   FROM aggregated_volume;


